import * as React from 'react';
import clsx from 'clsx';
import { RcMenuContext } from '../context/MenuContext';

export interface RcSubMenuListProps extends React.HTMLAttributes<HTMLUListElement> {
  children?: React.ReactNode;
}

const InternalSubMenuList = (
  { className, children, ...restProps }: RcSubMenuListProps,
  ref: React.Ref<HTMLUListElement>,
) => {
  const { prefixCls, mode } = React.useContext(RcMenuContext)!;

  return (
    <ul
      className={clsx(
        prefixCls,
        `${prefixCls}-sub`,
        `${prefixCls}-${mode === 'inline' ? 'inline' : 'vertical'}`,
        className,
      )}
      {...restProps}
      data-menu-list
      ref={ref}
    >
      {children}
    </ul>
  );
};

const RcSubMenuList = React.forwardRef(InternalSubMenuList);
RcSubMenuList.displayName = 'SubMenuList';

export default RcSubMenuList;
